    }}
    .eyebrow {{ font-size:13px; font-weight:800; letter-spacing:.08em; opacity:.82; text-transform:uppercase; }}
    h1 {{ margin:8px 0 10px; font-size:34px; line-height:1.2; letter-spacing:0; }}
    h2 {{ margin:0; font-size:22px; line-height:1.25; letter-spacing:0; }}
    h3 {{ margin:0 0 8px; font-size:16px; line-height:1.35; letter-spacing:0; }}
    p {{ margin:0; }}
    .grid {{ display:grid; gap:18px; margin-top:22px; }}
    .two {{ grid-template-columns:1fr 1fr; }}
    .section {{
      background:var(--card);
      border:1px solid var(--line);
      border-radius:14px;
      padding:24px;
      box-shadow:0 10px 26px rgba(20, 32, 60, .06);
    }}
    .section-title {{ display:flex; gap:12px; align-items:flex-start; margin-bottom:18px; }}
    .section-title:before {{
      content:"";
      width:5px;
      height:30px;
      border-radius:999px;
      background:var(--primary);
      flex:none;
      margin-top:2px;
    }}
    .hint {{ color:var(--muted); margin-top:8px; font-size:14px; }}
    .flow {{ display:grid; gap:12px; }}
    .flow-step {{
      border:1px solid var(--line);
      border-left:5px solid var(--primary);
      border-radius:12px;
      padding:15px 16px;
      background:#fff;
    }}
    .badges {{ display:flex; gap:8px; flex-wrap:wrap; margin-bottom:8px; }}
    .badge {{
      display:inline-flex;
      padding:3px 9px;
      border-radius:999px;
      background:#edf0ff;
      color:#3346c4;
      font-size:12px;
      font-weight:700;
    }}
    .badge.subtle {{ background:#f1f4f9; color:#536074; }}
    .cards {{ display:grid; grid-template-columns:repeat(3, minmax(0, 1fr)); gap:12px; }}
    .cap-card {{
      border:1px solid var(--line);
      border-radius:12px;
      padding:15px;
      background:var(--soft);
      min-height:142px;
    }}
    .blueprint {{ display:grid; gap:16px; }}
    .blueprint-card {{
      border:1px solid var(--line);
      border-radius:14px;
      background:#fff;
      padding:18px;
    }}
    .blueprint-head {{ display:flex; gap:12px; align-items:flex-start; justify-content:space-between; margin-bottom:14px; }}
    .blueprint-head h3 {{ font-size:18px; }}
    .spec-grid {{ display:grid; grid-template-columns:1fr 1fr; gap:12px; margin-top:12px; }}
    .spec-box {{ border:1px solid var(--line); border-radius:12px; background:var(--soft); padding:13px; }}
    .spec-box strong {{ display:block; margin-bottom:6px; font-size:13px; color:#3346c4; }}
    .cap-list {{ display:grid; gap:10px; margin-top:12px; }}
    .cap-spec {{ border:1px solid var(--line); border-radius:12px; padding:13px; background:#fff; }}
    .cap-spec h4 {{ margin:0 0 6px; font-size:15px; }}
    .muted {{ color:var(--muted); }}
    .links {{ margin-top:10px; display:flex; gap:8px; flex-wrap:wrap; }}
    .links a {{ color:#3346c4; font-weight:700; text-decoration:none; font-size:13px; }}
    .list {{ margin:0; padding-left:20px; }}
    .list li + li {{ margin-top:9px; }}
    .list span {{ display:block; color:var(--muted); margin-top:2px; }}
    .danger {{ border-color:#fecdca; }}
    .danger .section-title:before {{ background:var(--danger); }}
    .footer {{ margin-top:18px; color:var(--muted); font-size:12px; }}
    @media (max-width: 900px) {{
      .page {{ padding:18px; }}
