            mongo_uri=getattr(self, "mongo_uri", ""),
            db_name=getattr(self, "db_name", DEFAULT_DB_NAME),
            capability_collection=getattr(self, "capability_collection", DEFAULT_CAPABILITY_COLLECTION),
