    return [value]


class CatalogStoreSummary(Component):
    display_name = "2.5 카탈로그 저장 결과 출력"
    description = "MongoDB 카탈로그 저장 결과를 사람이 읽기 쉬운 메시지로 출력합니다."
    icon = "MessageCircle"
    inputs = [DataInput(name="store_result", display_name="저장 결과", required=True)]
